import mongoose, { Schema, Document } from 'mongoose';

interface IUser extends Document {
  name: string;
  email: string;
  createdAt: Date;
}

const UserSchema = new Schema<IUser>({
  name:  { type: String, required: true, trim: true },
  email: { type: String, required: true, unique: true, lowercase: true },
}, { timestamps: true });

export const User = mongoose.model<IUser>('User', UserSchema);

await mongoose.connect(process.env.MONGODB_URI!);

// Create
const alice = await User.create({ name: 'Alice', email: 'alice@example.com' });

// Query
const users = await User.find({ name: /alice/i }).sort('-createdAt').limit(10);

// Update
await User.updateOne({ _id: alice._id }, { $set: { name: 'Alice B.' } });

// Delete
await User.deleteOne({ _id: alice._id });
